import{_ as t,o as a,c as s,ag as i}from"./chunks/framework._658-eYr.js";const d=JSON.parse(`{"title":"Why Black Holes Aren't Actually Black","description":"","frontmatter":{"id":"script-002","title":"Why Black Holes Aren't Actually Black","type":"long","status":"draft","tags":["space","physics","black holes","hawking radiation"],"created":"2026-02-22T09:00:00.000Z","updated":"2026-02-22T09:00:00.000Z","word_count":310},"headers":[],"relativePath":"fixtures/channels/lorem-ipsum-tech/scripts/drafts/script-002.md","filePath":"fixtures/channels/lorem-ipsum-tech/scripts/drafts/script-002.md"}`),r={name:"fixtures/channels/lorem-ipsum-tech/scripts/drafts/script-002.md"};function n(o,e,l,h,p,c){return a(),s("div",null,[...e[0]||(e[0]=[i('<p><em>(Open on starfield animation, slow zoom into a dark region)</em></p><p><strong>Alex:</strong> Picture this: you&#39;re standing at the edge of a black hole. Behind you, the entire observable universe is compressed into a tiny bright ring. In front of you... nothing. Absolute nothing.</p><p>Except — and this is the part that broke Stephen Hawking&#39;s brain — it&#39;s not actually nothing.</p><h3 id="the-great-escape" tabindex="-1">The Great Escape <a class="header-anchor" href="#the-great-escape" aria-label="Permalink to &quot;The Great Escape&quot;">​</a></h3><p>Here&#39;s the standard explanation: black holes are so massive that nothing can escape their gravity. Not even light. Hence: black.</p><p>But in 1974, Hawking realized something bizarre. Quantum mechanics says that empty space isn&#39;t really empty. It&#39;s constantly fizzing with pairs of particles that pop into existence and immediately annihilate each other.</p><p>Now imagine this happens right at the edge of a black hole — the event horizon. One particle falls in. The other escapes. From the outside, it looks like the black hole just <em>emitted</em> a particle.</p><p><em>(Animation showing particle pair at event horizon)</em></p><p><strong>Alex:</strong> This is Hawking radiation. And it means black holes aren&#39;t perfectly black. They glow. Very, very faintly.</p><h3 id="the-slow-death" tabindex="-1">The Slow Death <a class="header-anchor" href="#the-slow-death" aria-label="Permalink to &quot;The Slow Death&quot;">​</a></h3><p>Here&#39;s where it gets wild. Every time a particle escapes, the black hole loses a tiny bit of mass. Over incomprehensible timescales — we&#39;re talking longer than the current age of the universe — a black hole will eventually evaporate completely.</p><p>The biggest black holes will take 10^100 years to disappear. That number is so large it makes the age of the universe look like a rounding error.</p><p><strong>Alex:</strong> So black holes aren&#39;t eternal cosmic prisons. They&#39;re temporary. Just... very, very patient.</p><p><em>(Beat)</em></p><p>Everything ends. Even darkness.</p><p><em>Patch your systems.</em></p>',16)])])}const g=t(r,[["render",n]]);export{d as __pageData,g as default};
